function formatText(input) {
  const formatted = input
    .replace(/\*\*\*(.*?)\*\*\*/g, '$1')
    .replace(/\*\*(.*?)\*\*/g, '$1')
    .replace(/\*(.*?)\*/g, '$1')
    .replace(/\n/g, '<br>')
    .replace(/"/g, '&quot;');

  // return JSON.stringify(formatted);
  return formatted;
}

